import React from 'react'
import logo2 from '../images/logo2.png'
import logo1 from '../images/logo1.png'
import { Box, Button, Container, TextField, Link, Typography } from '@material-ui/core';
import { makeStyles } from '@material-ui/styles';

const useStyle = makeStyles(theme => ({
    root: {
        '& .MuiInputBase-root': {
            marginBottom: theme.spacing(1)
        },
        '& .MuiInputBase-input': {
            padding: theme.spacing(2)
        },
        '& .MuiLink-root': {
            textDecoration: 'none',
            color: '#162276',
            fontSize: '12px'
        }
    },
    formContainer: {
        display: 'fixed',
        padding: '22px',
        [theme.breakpoints.up('md')]: {
            display: 'block',
            boxShadow: '1px 1px 12px rgba(0,0,0,0.2),0px 2px 2px 0px rgba(0,0,0,0.14),0px 1px 5px 0px rgba(0,0,0,0.12)',
            maxWidth: '400px',
            borderRadius: '7px',
            marginTop: '10%'
        }
    },
    logoContainer: {
        maxWidth: '300px',
        margin: '0 auto'
    },
    logo: {
        width: '100%',
        paddingTop: '10%'
    },
    responsiveLogo1: {
        display: 'none',
        [theme.breakpoints.up('md')]: {
            display: 'block'
        }
    },
    responsiveLogo2: {
        display: 'none',
        [theme.breakpoints.down('sm')]: {
            display: 'block'
        }
    },
    form: {
        margin: '0 auto',
        maxWidth: '350px'
    },
    btn: {
        width: '100%',
        margin: '10px 0'
    }

}));

export default function Login() {
    const classes = useStyle();
    return (
        <Box className={classes.root}>
            <Container className={classes.formContainer}>
                <div className={classes.logoContainer}>
                    <Box className={classes.responsiveLogo1}>
                    <img className={classes.logo} src={logo1} alt="URSAC Online logo" />
                    </Box>
                    <Box className={classes.responsiveLogo2}>
                    <img className={classes.logo} src={logo2} alt="URSAC Online logo" />
                    </Box>
                </div>
                <div className={classes.form}>
                    <TextField placeholder='Student ID' variant='outlined' fullWidth />
                    <TextField placeholder='Password' variant='outlined' type='password' fullWidth />
                    <Button className={classes.btn} size='large' variant='contained' color='secondary'>
                        LOGIN
                    </Button>
                    <center>
                        <Typography>
                            <Link href="#">
                                Forgot Password?
                            </Link>
                        </Typography>
                        <Typography>
                            <Link href="#">
                                Teacher Login.
                            </Link>
                        </Typography>
                    </center>
                </div>
            </Container>
        </Box>
    )
}
